LFightBoutActionData.WARNING_CNT = 50

function LFightBoutActionData:InitJsonBoutActionData(json)
	self._aId = json.aId
	self._eId = json.eId
	self._skill = json.skill
	self._express = json.express

	local effect = json.effect or {}
	local eIdTarList = {}
	self._eIdTarList = eIdTarList

	---获取目标列表
	for k,v in ipairs(effect) do
		local list = v.list
		local listList = {}
		for k1,v1 in ipairs(list) do
			local effectList ={}
			effectList.eid = v1.eid
			effectList.list = {}
			for k2,v2 in ipairs(v1.list) do
				---@type LFightEffectData
				local teffect = LFightEffectData:New()
				teffect:CreateByJson(v2)
				table.insert(effectList.list,teffect)
			end
			table.insert(listList,effectList)
		end
		table.insert(eIdTarList,list)
	end
end


function LFightBoutActionData:InitPbBoutActionData(pb,lifeState)
	self._aId = pb.aId
	self._eId = pb.eId
	self._skill = pb.skill
	self._express = pb.express

	local effect = pb.effect or {}

	local eIdTarList = {}
	self._eIdTarList = eIdTarList


	local reliveType = gModelSkill:GetReliveSkillType(self._skill)
	if reliveType>0 then
		local map = lifeState[self._aId]
		if not map then
			map = {}
			lifeState[self._aId] = map
		end
		map[reliveType] = true
	end

	local cnt = nil

	for k,v in ipairs(effect) do
		local list = v.list
		local listList = {}
		for k1,v1 in ipairs(list) do
			local effectList ={}
			effectList.eid = v1.eId
			effectList.list = {}
			for k2,v2 in ipairs(v1.list) do
				local effect = LFightEffectData:New()
				effect:CreateByPb(v2)
				table.insert(effectList.list,effect)
			end

			cnt = #effectList.list
			if cnt > LFightBoutActionData.WARNING_CNT then
				printErrorN(string.format("effect list cnt %s",cnt))
			end

			table.insert(listList,effectList)
		end
		table.insert(eIdTarList,listList)
	end

end


