---@return boolean 判断是否连击
function LFightBoutActionData:CheckIsAllbo()
	local needShowNum = 0
	local eIdTarList = self:GetEffectList()
	if #eIdTarList < 1 then return false,needShowNum end

	local isAllbo = true
	local aId = self:GetAttackId()
	for i,v in ipairs(eIdTarList) do
		if not isAllbo then break end
		for _i,_v in ipairs(v) do
			if not isAllbo then break end
			for __i,effect in ipairs(_v.list) do
				if effect.type == LFightConst.ACTIONEFFECTENUM_HURT then
					local isOk = effect.hitType == 1
					if isOk then
						if aId ~= effect.aId then
							isAllbo = false
							break
						else
							needShowNum = needShowNum + 1
						end
					end
				end
			end
		end
	end
	if needShowNum == 1 then
		isAllbo = false
	end
	return isAllbo,needShowNum
end

function LFightBoutActionData:CheckPassiveSkillHasShow()
	local skillId = self:GetSkill()
	local skillRef = gModelSkill:GetSkillRef(skillId)
	if not skillRef or skillRef.type ~= 2 then return nil end

	local eIdTarList = self:GetEffectList()
	if #eIdTarList < 1 then return nil end

	local hasSkillShow = false
	for i,v in ipairs(eIdTarList) do
		if hasSkillShow then break end
		for _i,_v in ipairs(v) do
			if hasSkillShow then break end
			for __i,effect in ipairs(_v.list) do
				if effect.type == LFightConst.ACTIONEFFECTENUM_BUFF and effect.etype == LFightConst.BUFF_TYPE_ADD then
					if gModelSkill:IsShowSorceryEff(effect.buffId) then
						hasSkillShow = true
					end
				end
			end
		end
	end
	if not hasSkillShow then return nil end

	if not gModelSorceryCard:CheckIsSorcerySkill(skillId) then return nil end

	local skillExpressList = gModelSkill:GetExpressionList(skillId)
	if not skillExpressList or #skillExpressList < 1 then return nil end

	local firstSkillExpress = skillExpressList[1]
	local expressionId = firstSkillExpress.expressionId
	local skinTempRefId = gModelSkill:GetSkinExpress(0,expressionId,true)
	return skinTempRefId
end

